config.providers = config.providers.map((provider) => {
  const { id } = typeof provider === "function" ? provider({}) : provider
  const ID = id.toUpperCase().replace(/-/g, "_")
  const clientId = envObject[`AUTH_${ID}_ID`]
  const clientSecret = envObject[`AUTH_${ID}_SECRET`]
  const issuer = envObject[`AUTH_${ID}_ISSUER`]
  const apiKey = envObject[`AUTH_${ID}_KEY`]
  const finalProvider =
    typeof provider === "function"
      ? provider({ clientId, clientSecret, issuer, apiKey })
      : provider
  if (finalProvider.type === "oauth" || finalProvider.type === "oidc") {
    finalProvider.clientId ??= clientId
    finalProvider.clientSecret ??= clientSecret
    finalProvider.issuer ??= issuer
  } else if (finalProvider.type === "email") {
    finalProvider.apiKey ??= apiKey
  }
  return finalProvider
})

return (
  <Script
    id="design-system-listener"
    strategy="beforeInteractive"
    dangerouslySetInnerHTML={{
      __html: `
          (function() {
            // Forward Cmd/Ctrl + K (and P) to parent
            document.addEventListener('keydown', function(e) {
              if ((e.key === 'k' || e.key === 'p') && (e.metaKey || e.ctrlKey)) {
                e.preventDefault();
                if (window.parent && window.parent !== window) {
                  window.parent.postMessage({
                    type: '${CMD_K_FORWARD_TYPE}',
                    key: e.key
                  }, '*');
                }
              }
            });

          })();
        `,
    }}
  />
)

const applyCommands = React.useMemo(() => {
    const presetFlag = ` --preset ${presetCode}`
    const onlyFlag =
      applyMode === "theme"
        ? " --only theme"
        : applyMode === "font"
          ? " --only font"
          : ""
    const flags = `${presetFlag}${onlyFlag}`

    return IS_LOCAL_DEV
      ? {
          pnpm: `shadcn apply${flags}`,
          npm: `shadcn apply${flags}`,
          yarn: `shadcn apply${flags}`,
          bun: `shadcn apply${flags}`,
        }
      : {
          pnpm: `pnpm dlx shadcn${SHADCN_VERSION} apply${flags}`,
          npm: `npx shadcn${SHADCN_VERSION} apply${flags}`,
          yarn: `yarn dlx shadcn${SHADCN_VERSION} apply${flags}`,
          bun: `bunx --bun shadcn${SHADCN_VERSION} apply${flags}`,
        }
  }, [applyMode, presetCode])

